import{U as e,gt as t,nt as n,rt as r}from"./chunks/framework.B3obAz7o.js";var i=JSON.parse(`{"title":"功能概览","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/features.md","filePath":"zh/guide/features.md","lastUpdated":1784191277000}`),a={name:`zh/guide/features.md`};function o(e,i,a,o,s,c){return t(),n(`div`,null,[...i[0]||=[r(`<h1 id="功能概览" tabindex="-1">功能概览 <a class="header-anchor" href="#功能概览" aria-label="Permalink to “功能概览”">​</a></h1><p>fontmin-rs 目前处于 beta 阶段。本页集中记录已经实现的公开能力，以及选择不同入口时需要了解的边界。第一次使用时，可以继续阅读<a href="./getting-started">快速开始</a>。</p><h2 id="使用入口" tabindex="-1">使用入口 <a class="header-anchor" href="#使用入口" aria-label="Permalink to “使用入口”">​</a></h2><table tabindex="0"><thead><tr><th>入口</th><th>适用场景</th><th>Runtime 模型</th></tr></thead><tbody><tr><td><code>fontmin-rs</code> CLI</td><td>Shell 脚本、CI、单次处理</td><td>原生 Rust 可执行文件</td></tr><tr><td><code>fontmin-rs</code> Node API</td><td>构建集成和自定义流水线</td><td>Native binding、强制 WASM 或 native-first auto</td></tr><tr><td><code>@fontmin-rs/wasm</code></td><td>浏览器和 Worker 应用</td><td>异步、纯内存 WASM</td></tr></tbody></table><p>npm 包还提供同名 CLI、类型化配置 helpers、内置插件声明、presets，以及 Fontmin-compatible chain。</p><h2 id="字体处理能力" tabindex="-1">字体处理能力 <a class="header-anchor" href="#字体处理能力" aria-label="Permalink to “字体处理能力”">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>支持的操作</th></tr></thead><tbody><tr><td>字体子集化</td><td>按文本、文本文件、Unicode code point、basic text 或 Unicode range 分组保留字形。</td></tr><tr><td>Web 字体转换</td><td>TTF 与 WOFF、WOFF2 互转，并支持 WOFF metadata 和 private data block。</td></tr><tr><td>遗留格式转换</td><td>TTF 与 EOT 互转、TTF 转 SVG font、SVG font 转 TTF。</td></tr><tr><td>OpenType 转换</td><td>将静态 CFF OTF 或 CFF2 variable OTF 实例化为静态 TrueType <code>glyf</code> 字体。</td></tr><tr><td>Icon font</td><td>将多个 SVG icon 合并为 TTF，并按需生成 glyph class CSS。</td></tr><tr><td>CSS 生成</td><td>生成 <code>@font-face</code> CSS、SCSS 或 Less，支持 local source、Base64 和 <code>unicode-range</code>。</td></tr><tr><td>字体信息检查</td><td>检测并读取 TTF、OTF、WOFF、WOFF2 和 EOT metadata。</td></tr></tbody></table><p>Node 与浏览器的低层 API 可以直接调用这些操作；文件流水线则通过内置插件组合相同能力。完整可调用接口请查看 <a href="./../api/node">Node API</a> 和<a href="./../api/wasm">浏览器 WASM API</a>。</p><h2 id="流水线与-preset" tabindex="-1">流水线与 Preset <a class="header-anchor" href="#流水线与-preset" aria-label="Permalink to “流水线与 Preset”">​</a></h2><ul><li><code>optimize(config)</code> 在 Node.js 中发现文件输入、执行插件、复用匹配的缓存并写出产物。</li><li><code>optimizeBrowser(config)</code> 对命名的内存资产执行内置或自定义浏览器插件，不访问文件系统。</li><li><code>modernWeb(options)</code> 会规范化受支持的 OTF 输入、提取子集，并输出 WOFF、WOFF2 和 CSS。</li><li><code>fontminCompatPreset(options)</code> 按经典 Fontmin 顺序输出 EOT、SVG、WOFF、WOFF2 和 CSS。</li><li>CLI <code>iconfont</code> preset 会将多个 SVG icon 合并为 <code>iconfont.ttf</code> 和 <code>iconfont.css</code>。</li><li><code>deliverySlices()</code> 与 CLI delivery slices 会生成命名子集及对应的 CSS <code>unicode-range</code> 描述。</li></ul><p>内置插件 factories 包括 <code>glyph</code>、<code>deliverySlices</code>、<code>otf2ttf</code>、<code>ttf2woff</code>、 <code>ttf2woff2</code>、<code>ttf2eot</code>、<code>ttf2svg</code>、<code>svg2ttf</code>、<code>svgs2ttf</code> 和 <code>css</code>。</p><p>Node <code>optimize(config)</code> 会为整条流水线选择同一个内置 runtime：<code>native</code>、<code>wasm</code> 或 native-first <code>auto</code>。缓存会按所选 runtime 隔离；文件系统操作和自定义 JavaScript hooks 始终留在 Node.js 中执行。</p><h2 id="cli-与配置文件" tabindex="-1">CLI 与配置文件 <a class="header-anchor" href="#cli-与配置文件" aria-label="Permalink to “CLI 与配置文件”">​</a></h2><p>CLI 提供 <code>init</code>、<code>subset</code>、<code>convert</code>、<code>build</code>、<code>bench</code>、<code>inspect</code> 和 <code>doctor</code> 命令。它可以加载 JSON、JSONC、TS、MTS、MJS 和 CJS 配置文件；可执行的 module config 需要 Node.js 22 或更高版本。</p><p>命令参数和示例请查看<a href="./cli">命令行</a>。配置文件发现、输出控制、缓存、子集化模式、OTF variation coordinates，以及 Rust built-ins 与自定义 Node.js plugins 的边界，请查看<a href="./config">配置文件</a>。</p><h2 id="兼容性与限制" tabindex="-1">兼容性与限制 <a class="header-anchor" href="#兼容性与限制" aria-label="Permalink to “兼容性与限制”">​</a></h2><ul><li>EOT 仅用于旧版 Internet Explorer 兼容；现代项目通常应首选 WOFF2，并用 WOFF 作为 fallback。</li><li>CFF/CFF2 转换始终输出静态 TTF；variation tables 会被移除，Type 2 hinting 不会保留。</li><li><code>modernWeb()</code> 只输出 WOFF、WOFF2 和 CSS。需要遗留格式时应显式添加插件，或使用 <code>fontminCompatPreset()</code>。</li><li>浏览器包不支持路径输入、glob、CLI、磁盘缓存、输出目录或文件系统 hooks。</li><li>自定义 Node.js plugins 可以使用文件系统和 diagnostics context helpers；浏览器 plugins 只有更小的纯内存 hook surface。</li></ul><p>Fontmin 用户可以阅读<a href="./migration">从 Fontmin 迁移</a>。内部包结构和 runtime 边界请查看<a href="./../architecture">项目架构</a>。</p><h2 id="项目状态" tabindex="-1">项目状态 <a class="header-anchor" href="#项目状态" aria-label="Permalink to “项目状态”">​</a></h2><p>当前开发重点是发布加固、改进 diagnostics、性能优化，以及覆盖更多 Fontmin 兼容能力。长期方向记录在<a href="./../../fontmin-rs-design">设计文档</a>中；维护者可以使用<a href="./../../releasing">发布准备清单</a>检查候选版本是否达到发布门槛。</p>`,20)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};